diff --git a/llvm/include/llvm/IR/Instructions.h b/llvm/include/llvm/IR/Instructions.h
index 6f69b68f628f..fc8f54e2dadc 100644
--- a/llvm/include/llvm/IR/Instructions.h
+++ b/llvm/include/llvm/IR/Instructions.h
@@ -1459,6 +1459,16 @@ public:
   /// Determine if this is an equality predicate.
   bool isEquality() const { return isEquality(getPredicate()); }

+  /// @returns true if the predicate is an ordered equality predicate (OEQ or ONE).
+  /// Determine if this is an ordered equality predicate.
+  static bool isOrderedEquality(Predicate Pred) {
+    return Pred == FCMP_OEQ || Pred == FCMP_ONE;
+  }
+
+  /// @returns true if the predicate of this instruction is an ordered equality.
+  /// Determine if this is an ordered equality predicate.
+  bool isOrderedEquality() const { return isOrderedEquality(getPredicate()); }
+
   /// @returns true if the predicate is commutative.
   /// Determine if this is a commutative predicate.
   static bool isCommutative(Predicate Pred) {
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index c112fae35181..e0a5ec15be48 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8638,6 +8638,18 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       if (FCmpInst::isEquality(Pred) && match(RHSC, m_AnyZeroFP()) &&
           match(LHSI, m_c_Select(m_FNeg(m_Value(X)), m_Deferred(X))))
         return replaceOperand(I, 0, X);
+      // fcmp oeq (select (fcmp ord X, 0.0), X, 0.0), C --> fcmp oeq X, C
+      // If X is NaN: select gives 0.0, and (0.0 == C) is false (same as NaN == C)
+      // If X is not NaN: select gives X, and (X == C) is what we want
+      // This is valid only when C != 0.0 (the false value)
+      if (FCmpInst::isOrderedEquality(Pred) &&
+          match(LHSI, m_Select(m_SpecificFCmp(FCmpInst::FCMP_ORD, m_Value(X), m_AnyZeroFP()),
+                               m_Deferred(X), m_AnyZeroFP()))) {
+        const APFloat *CFP;
+        if (match(RHSC, m_APFloat(CFP)) && !CFP->isZero()) {
+          return new FCmpInst(Pred, X, RHSC, "", &I);
+        }
+      }
       if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
         return NV;
       break;

